1	// Package evidencelint implements the no-unbounded-prompts structural lint
2	// rule for FEAT-022. It flags four sink patterns that route runtime data
3	// into agent prompts or prompt-adjacent server text egress without going
4	// through the internal/evidence primitives:
5	//
6	//  1. Assignment to a *.Prompt selector whose receiver type is the
7	//     agent.RunOptions struct (or a struct embedding it).
8	//  2. Composite-literal construction of mcpContent{Type: "text", ...}.
9	//  3. os.ReadFile / ioutil.ReadFile / io/ioutil.ReadFile result flowing
10	//     directly into a variable whose name matches *prompt* / *Prompt*.
11	//  4. Calls to response-writer methods (Write, WriteString, Fprintf,
12	//     Encoder.Encode) inside server packages whose data argument
13	//     references library / exec / diff / session / persona source
14	//     packages.
15	//
16	// Static/literal prompt fragments compiled into the binary are exempt.
17	//
18	// A flagged path may be intentionally exempted by adding an
19	//
20	//	// evidence:allow-unbounded reason="..."
21	//
22	// comment on the same line as the offending node, or on a comment line
23	// directly above it. The reason= clause must be present and non-empty.
24	package evidencelint
25	
26	import (
27		"go/ast"
28		"go/token"
29		"go/types"
30		"strings"
31	
32		"golang.org/x/tools/go/analysis"
33		"golang.org/x/tools/go/analysis/passes/inspect"
34		"golang.org/x/tools/go/ast/inspector"
35	)
36	
37	const annotation = "evidence:allow-unbounded"
38	
39	// Analyzer is the FEAT-022 structural sink analyzer.
40	var Analyzer = &analysis.Analyzer{
41		Name:     "evidencelint",
42		Doc:      "flags unbounded prompt sinks per FEAT-022 §3 (no-unbounded-prompts invariant)",
43		Requires: []*analysis.Analyzer{inspect.Analyzer},
44		Run:      run,
45	}
46	
47	// runOptionsTypeNames lists the named types whose .Prompt field
48	// assignment is a sink. RunOptions is the canonical case; embedding
49	// types (QuorumOptions, EmbeddedAgentOptions, etc.) are matched
50	// transitively via field lookup on the embedded type.
51	var runOptionsTypeNames = map[string]bool{
52		"RunOptions": true,
53	}
54	
55	// runOptionsPkgSuffixes lists package import-path suffixes whose
56	// RunOptions named type is the prompt sink we care about. Prevents
57	// false positives on identically named types in unrelated packages.
58	var runOptionsPkgSuffixes = []string{"/agent", "agent"}
59	
60	// mcpContentTypeName is the named type whose composite-literal
61	// construction with Type:"text" is a sink.
62	const mcpContentTypeName = "mcpContent"
63	
64	// mcpContentPkgSuffixes lists package import-path suffixes whose
65	// mcpContent named type is the prompt-adjacent egress sink.
66	var mcpContentPkgSuffixes = []string{"/server", "server", "mcppkg"}
67	
68	// sourcePkgSuffixes lists the source-package import-path suffixes
69	// considered library/exec/diff/session/persona content for the §10
70	// bounded-egress rule. Conservative structural match.
71	var sourcePkgSuffixes = []string{
72		"/library", "library",
73		"/exec", "exec",
74		"/diff", "diff",
75		"/session", "session",
76		"/persona", "persona",
77		"/libdoc", "libdoc",
78	}
79	
80	// serverPkgSuffixes lists the package import-path suffixes considered
81	// HTTP-handler-bearing server packages.
82	var serverPkgSuffixes = []string{
83		"/server", "server",
84		"/graphql", "graphql",
85	}
86	
87	// responseWriterMethods are method names whose receiver is treated as
88	// a response-writer sink for pattern 4.
89	var responseWriterMethods = map[string]bool{
90		"Write":       true,
91		"WriteString": true,
92		"Fprintf":     true,
93		"Fprint":      true,
94		"Fprintln":    true,
95		"Encode":      true,
96	}
97	
98	func pkgPathHasSuffix(p string, suffixes []string) bool {
99		for _, s := range suffixes {
100			if p == s || strings.HasSuffix(p, s) {
101				return true
102			}
103		}
104		return false
105	}
106	
107	func run(pass *analysis.Pass) (interface{}, error) {
108		insp := pass.ResultOf[inspect.Analyzer].(*inspector.Inspector)
109	
110		// Collect all annotation comments (file → line → reason).
111		allow := collectAllowAnnotations(pass)
112	
113		report := func(pos token.Pos, msg string) {
114			if isAllowed(pass.Fset, pos, allow) {
115				return
116			}
117			pass.Report(analysis.Diagnostic{
118				Pos:     pos,
119				Message: msg,
120			})
121		}
122	
123		// Skip the analyzer's own package and tests directory.
124		if pass.Pkg != nil {
125			path := pass.Pkg.Path()
126			if strings.HasSuffix(path, "/tools/lint/evidencelint") ||
127				strings.Contains(path, "/tools/lint/evidencelint/") {
128				return nil, nil
129			}
130		}
131	
132		// Pattern 1 & 3: AssignStmt walks
133		insp.Preorder([]ast.Node{(*ast.AssignStmt)(nil)}, func(n ast.Node) {
134			as := n.(*ast.AssignStmt)
135			checkPromptAssignment(pass, as, report)
136			checkReadFileToPromptVar(pass, as, report)
137		})
138	
139		// Pattern 2: mcpContent composite literals
140		insp.Preorder([]ast.Node{(*ast.CompositeLit)(nil)}, func(n ast.Node) {
141			cl := n.(*ast.CompositeLit)
142			checkMCPContent(pass, cl, report)
143		})
144	
145		// Pattern 4: response-writer calls inside server packages
146		if pass.Pkg != nil && pkgPathHasSuffix(pass.Pkg.Path(), serverPkgSuffixes) {
147			insp.Preorder([]ast.Node{(*ast.CallExpr)(nil)}, func(n ast.Node) {
148				ce := n.(*ast.CallExpr)
149				checkServerWrite(pass, ce, report)
150			})
151		}
152	
153		return nil, nil
154	}
155	
156	// --- Pattern 1: assignment to RunOptions.Prompt ----------------------------
157	
158	func checkPromptAssignment(pass *analysis.Pass, as *ast.AssignStmt, report func(token.Pos, string)) {
159		for _, lhs := range as.Lhs {
160			sel, ok := lhs.(*ast.SelectorExpr)
161			if !ok || sel.Sel == nil || sel.Sel.Name != "Prompt" {
162				continue
163			}
164			// Resolve the type of sel.X.
165			t := pass.TypesInfo.TypeOf(sel.X)
166			if t == nil {
167				continue
168			}
169			if !typeIsRunOptions(t) {
170				continue
171			}
172			// Allow assignment where the RHS is a constant string expression.
173			if len(as.Rhs) == 1 && isConstantString(pass, as.Rhs[0]) {
174				continue
175			}
176			report(sel.Pos(),
177				"evidencelint: assignment to RunOptions.Prompt without going through internal/evidence primitives (FEAT-022 §3); add `// evidence:allow-unbounded reason=\"...\"` to suppress")
178		}
179	}
180	
181	func typeIsRunOptions(t types.Type) bool {
182		// Strip pointers.
183		for {
184			p, ok := t.(*types.Pointer)
185			if !ok {
186				break
187			}
188			t = p.Elem()
189		}
190		named, ok := t.(*types.Named)
191		if !ok {
192			return false
193		}
194		obj := named.Obj()
195		if obj == nil {
196			return false
197		}
198		if !runOptionsTypeNames[obj.Name()] {
199			// Not RunOptions itself; check if the underlying struct embeds RunOptions.
200			st, ok := named.Underlying().(*types.Struct)
201			if !ok {
202				return false
203			}
204			for i := 0; i < st.NumFields(); i++ {
205				f := st.Field(i)
206				if !f.Anonymous() {
207					continue
208				}
209				if typeIsRunOptions(f.Type()) {
210					return true
211				}
212			}
213			return false
214		}
215		if obj.Pkg() == nil {
216			return false
217		}
218		return pkgPathHasSuffix(obj.Pkg().Path(), runOptionsPkgSuffixes)
219	}
220	
221	func isConstantString(pass *analysis.Pass, e ast.Expr) bool {
222		tv, ok := pass.TypesInfo.Types[e]
223		if !ok {
224			return false
225		}
226		return tv.Value != nil && tv.Value.Kind().String() == "String"
227	}
228	
229	// --- Pattern 2: mcpContent{Type:"text", ...} composite literal -------------
230	
231	func checkMCPContent(pass *analysis.Pass, cl *ast.CompositeLit, report func(token.Pos, string)) {
232		// Use the type-checker's view of the literal itself; this handles
233		// elided types in nested array/slice composite literals where
234		// cl.Type is nil but the element type is known.
235		t := pass.TypesInfo.TypeOf(cl)
236		if t == nil {
237			return
238		}
239		if ptr, ok := t.(*types.Pointer); ok {
240			t = ptr.Elem()
241		}
242		named, ok := t.(*types.Named)
243		if !ok {
244			return
245		}
246		obj := named.Obj()
247		if obj == nil || obj.Name() != mcpContentTypeName {
248			return
249		}
250		if obj.Pkg() == nil || !pkgPathHasSuffix(obj.Pkg().Path(), mcpContentPkgSuffixes) {
251			return
252		}
253		// Look for Type: "text" in the literal.
254		hasTextType := false
255		for _, elt := range cl.Elts {
256			kv, ok := elt.(*ast.KeyValueExpr)
257			if !ok {
258				continue
259			}
260			k, ok := kv.Key.(*ast.Ident)
261			if !ok || k.Name != "Type" {
262				continue
263			}
264			if lit, ok := kv.Value.(*ast.BasicLit); ok && lit.Kind == token.STRING && strings.Trim(lit.Value, "\"`") == "text" {
265				hasTextType = true
266				break
267			}
268		}
269		if !hasTextType {
270			return
271		}
272		report(cl.Pos(),
273			"evidencelint: mcpContent{Type:\"text\"} literal must route Text through evidence.ClampOutput (FEAT-022 §10); add `// evidence:allow-unbounded reason=\"...\"` to suppress")
274	}
275	
276	// --- Pattern 3: os.ReadFile result flowing into a *prompt* variable --------
277	
278	func checkReadFileToPromptVar(pass *analysis.Pass, as *ast.AssignStmt, report func(token.Pos, string)) {
279		if len(as.Rhs) != 1 {
280			return
281		}
282		call, ok := as.Rhs[0].(*ast.CallExpr)
283		if !ok {
284			return
285		}
286		if !isReadFileCall(call) {
287			return
288		}
289		for _, lhs := range as.Lhs {
290			ident, ok := lhs.(*ast.Ident)
291			if !ok || ident.Name == "_" {
292				continue
293			}
294			if !nameLooksLikePrompt(ident.Name) {
295				continue
296			}
297			report(call.Pos(),
298				"evidencelint: os.ReadFile/ioutil.ReadFile result flows into prompt-named variable without evidence.ReadFileClamped (FEAT-022 §8); add `// evidence:allow-unbounded reason=\"...\"` to suppress")
299			return
300		}
301	}
302	
303	func isReadFileCall(call *ast.CallExpr) bool {
304		sel, ok := call.Fun.(*ast.SelectorExpr)
305		if !ok {
306			return false
307		}
308		if sel.Sel == nil || sel.Sel.Name != "ReadFile" {
309			return false
310		}
311		pkg, ok := sel.X.(*ast.Ident)
312		if !ok {
313			return false
314		}
315		return pkg.Name == "os" || pkg.Name == "ioutil"
316	}
317	
318	func nameLooksLikePrompt(name string) bool {
319		lower := strings.ToLower(name)
320		return strings.Contains(lower, "prompt")
321	}
322	
323	// --- Pattern 4: server-package response writes from source packages --------
324	
325	func checkServerWrite(pass *analysis.Pass, ce *ast.CallExpr, report func(token.Pos, string)) {
326		sel, ok := ce.Fun.(*ast.SelectorExpr)
327		if !ok || sel.Sel == nil {
328			return
329		}
330		if !responseWriterMethods[sel.Sel.Name] {
331			return
332		}
333		// The data argument(s) we examine. For Encode/WriteString/Write,
334		// it's typically the first arg; for Fprintf it's args[1:]. Be
335		// permissive: scan all args.
336		for _, arg := range ce.Args {
337			if argReferencesSourcePkg(pass, arg) {
338				report(ce.Pos(),
339					"evidencelint: server response writer called with data sourced from library/exec/diff/session/persona without evidence.ClampOutput (FEAT-022 §10); add `// evidence:allow-unbounded reason=\"...\"` to suppress")
340				return
341			}
342		}
343	}
344	
345	// argReferencesSourcePkg returns true if the expression structurally
346	// references a function call or selector whose qualified identifier's
347	// package path matches one of the source-package suffixes.
348	func argReferencesSourcePkg(pass *analysis.Pass, e ast.Expr) bool {
349		found := false
350		ast.Inspect(e, func(n ast.Node) bool {
351			if found {
352				return false
353			}
354			switch x := n.(type) {
355			case *ast.SelectorExpr:
356				id, ok := x.X.(*ast.Ident)
357				if !ok {
358					return true
359				}
360				obj := pass.TypesInfo.ObjectOf(id)
361				if obj == nil {
362					return true
363				}
364				pkgName, ok := obj.(*types.PkgName)
365				if !ok {
366					return true
367				}
368				imp := pkgName.Imported()
369				if imp == nil {
370					return true
371				}
372				if pkgPathHasSuffix(imp.Path(), sourcePkgSuffixes) {
373					found = true
374					return false
375				}
376			}
377			return true
378		})
379		return found
380	}
381	
382	// --- Allow-annotation handling ---------------------------------------------
383	
384	// allowSet maps file name → set of line numbers whose adjacent annotation
385	// comment is "valid" (i.e. has a non-empty reason="...").
386	type allowSet map[string]map[int]bool
387	
388	func collectAllowAnnotations(pass *analysis.Pass) allowSet {
389		out := allowSet{}
390		for _, f := range pass.Files {
391			fname := pass.Fset.File(f.Pos()).Name()
392			lines := map[int]bool{}
393			for _, cg := range f.Comments {
394				for _, c := range cg.List {
395					text := c.Text
396					if !strings.Contains(text, annotation) {
397						continue
398					}
399					if !hasNonEmptyReason(text) {
400						continue
401					}
402					line := pass.Fset.Position(c.Pos()).Line
403					lines[line] = true
404					// Also mark the line(s) immediately below (covers
405					// "comment above the offending statement").
406					lines[line+1] = true
407				}
408			}
409			out[fname] = lines
410		}
411		return out
412	}
413	
414	// hasNonEmptyReason returns true if the comment text contains
415	// reason="..." with at least one non-quote character inside.
416	func hasNonEmptyReason(text string) bool {
417		idx := strings.Index(text, "reason=")
418		if idx < 0 {
419			return false
420		}
421		rest := text[idx+len("reason="):]
422		rest = strings.TrimLeft(rest, " \t")
423		if !strings.HasPrefix(rest, "\"") {
424			return false
425		}
426		rest = rest[1:]
427		end := strings.Index(rest, "\"")
428		if end <= 0 {
429			return false
430		}
431		return strings.TrimSpace(rest[:end]) != ""
432	}
433	
434	func isAllowed(fset *token.FileSet, pos token.Pos, allow allowSet) bool {
435		p := fset.Position(pos)
436		lines, ok := allow[p.Filename]
437		if !ok {
438			return false
439		}
440		return lines[p.Line]
441	}
