1	package evidencelint
2	
3	import (
4		"testing"
5	
6		"golang.org/x/tools/go/analysis/analysistest"
7	)
8	
9	// TestViolations runs the analyzer against fixtures that introduce one
10	// unannotated instance of each of the four sink patterns. The "// want"
11	// comments in the fixtures pin each expected diagnostic to its line.
12	func TestViolations(t *testing.T) {
13		dir := analysistest.TestData()
14		analysistest.Run(t, dir, Analyzer, "violations", "server")
15	}
16	
17	// TestAllowAnnotation runs the analyzer against fixtures where every
18	// violation carries a justifying evidence:allow-unbounded annotation.
19	// No diagnostics should be reported.
20	func TestAllowAnnotation(t *testing.T) {
21		dir := analysistest.TestData()
22		analysistest.Run(t, dir, Analyzer, "allowed")
23	}
24	
25	// TestEmptyReasonRejected verifies the parser requires a non-empty
26	// reason="..." clause: an annotation without one does not suppress.
27	func TestEmptyReasonRejected(t *testing.T) {
28		if hasNonEmptyReason(`// evidence:allow-unbounded reason=""`) {
29			t.Fatal("empty reason must not suppress")
30		}
31		if hasNonEmptyReason(`// evidence:allow-unbounded`) {
32			t.Fatal("missing reason must not suppress")
33		}
34		if !hasNonEmptyReason(`// evidence:allow-unbounded reason="legit"`) {
35			t.Fatal("non-empty reason must suppress")
36		}
37	}
